/* C:\Users\Edwin Boston\OneDrive\Desktop\III\STDLIB\corpus\1023_dispatch_pattern_slot_bounds.iii
 *
 * III conformance corpus 1023 -- dispatch/pattern slot bounds guards fire.
 *
 * Backlog item: codegen_dispatch-patterns-verify (#13).
 * Verdict: REFUTED_WITH_FACT -- all bounds are already enforced at the
 * pattern_table_get choke point and at tp_table_call/get_src/get_dst.
 * This KAT makes those guards permanently regression-tested with both
 * NEGATIVE (guard fires on bad input) and POSITIVE (good input passes)
 * arms, so the comparison has teeth.
 *
 * Guards exercised:
 *   A. pattern_register: slot >= PATTERN_REGISTRY_CAP (4096) -> 0
 *   B. pattern_register: slot >= PATTERN_REGISTRY_USED_MAX (100) -> 0
 *   C. pattern_table_get: idx >= PATTERN_REGISTRY_CAP (4096) -> 0
 *   D. pattern_table_get: pid == 0 (unregistered slot 70) -> 0
 *   E. tp_table_call: idx >= 24 -> 0 (fn-ptr is null, returns 0)
 *   F. tp_table_get_src: idx >= 24 -> 0u8
 *   G. POSITIVE: slot 5 (PRIMITIVE_COMPOSE) is registered after
 *      resolution_init(); tp_table_get_src(0u32) == 1u8.
 *
 * 99 = pass.
 */
module corpus_1023

extern @abi(c-msvc-x64) fn pattern_registry_unseal_for_test() -> i32 from "pattern_table.iii"
extern @abi(c-msvc-x64) fn pattern_register(slot: u32, template: u64) -> u8 from "pattern_table.iii"
extern @abi(c-msvc-x64) fn pattern_table_get(idx: u32) -> u64 from "pattern_table.iii"
extern @abi(c-msvc-x64) fn pattern_id(p: u64) -> u64 from "pattern_table.iii"
extern @abi(c-msvc-x64) fn pattern_registry_is_sealed() -> u8 from "pattern_table.iii"
extern @abi(c-msvc-x64) fn resolution_init() -> i32 from "resolution_init.iii"
extern @abi(c-msvc-x64) fn tp_table_call(idx: u32, src: u64, src_len: u64, dst: u64) -> u64 from "transform_patterns.iii"
extern @abi(c-msvc-x64) fn tp_table_get_src(idx: u32) -> u8 from "transform_patterns.iii"
extern @abi(c-msvc-x64) fn tp_table_get_dst(idx: u32) -> u8 from "transform_patterns.iii"

/* 168-byte dummy template buffer for pattern_register bound tests. */
var C1023_TEMPLATE : [u8; 168]

fn main() -> u64 {
    /* ---- PART 1: pattern_register bounds (guards A and B). --------
     * Unseal first so the sealed-registry check (which fires for the
     * WRONG reason post-seal) does not steal the test result. Then
     * re-seal by running resolution_init so Parts 3/4 work on a live
     * sealed registry. */
    pattern_registry_unseal_for_test()
    if pattern_registry_is_sealed() != 0u8 { return 1u64 }

    /* Guard A: slot >= PATTERN_REGISTRY_CAP (4096) must return 0. */
    let ra : u8 = pattern_register(4096u32, (&C1023_TEMPLATE) as u64)
    if ra != 0u8 { return 2u64 }  /* FALSIFIER: out-of-CAP slot accepted */

    /* Guard B: slot >= PATTERN_REGISTRY_USED_MAX (100) must return 0. */
    let rb : u8 = pattern_register(100u32, (&C1023_TEMPLATE) as u64)
    if rb != 0u8 { return 3u64 }  /* FALSIFIER: slot>=USED_MAX accepted */

    /* Slot just below USED_MAX (99) would be accepted if template had
     * a non-zero pid -- but we just want to confirm 100 is rejected,
     * not that 99 is accepted (template pid is 0 so pattern_table_get
     * would still return 0 for it, which is correct for Part D). */

    /* ---- PART 2: pattern_table_get bounds (guards C and D). -------
     * Registry may be sealed or unsealed -- both guards are independent
     * of seal state (CAP guard is first, pid-zero guard is second). */

    /* Guard C: idx >= PATTERN_REGISTRY_CAP (4096) must return 0u64. */
    let gc : u64 = pattern_table_get(4096u32)
    if gc != 0u64 { return 4u64 }  /* FALSIFIER: out-of-CAP index dereffed */

    /* Guard D: slot 70 is in [0,4096) but was never written (pid == 0).
     * pattern_table_get must return 0u64 (pid-zero path). */
    let gd : u64 = pattern_table_get(70u32)
    if gd != 0u64 { return 5u64 }  /* FALSIFIER: unregistered slot accepted */

    /* ---- PART 3: tp_table bounds (guards E and F). ----------------
     * resolution_init registers the 24 transform patterns at indices
     * 0..23 (slots 18..41).  Index 24 is one past the end. */
    if resolution_init() != 0i32 { return 6u64 }
    if pattern_registry_is_sealed() != 1u8 { return 7u64 }

    /* Guard E: tp_table_call with idx == 24 returns 0 (fn-ptr is null). */
    let te : u64 = tp_table_call(24u32, 0u64, 0u64, 0u64)
    if te != 0u64 { return 8u64 }  /* FALSIFIER: idx>=24 not rejected */

    /* Guard F: tp_table_get_src with idx == 24 returns 0u8. */
    let tf : u8 = tp_table_get_src(24u32)
    if tf != 0u8 { return 9u64 }   /* FALSIFIER: idx>=24 src non-zero */
    let tfd : u8 = tp_table_get_dst(24u32)
    if tfd != 0u8 { return 10u64 } /* FALSIFIER: idx>=24 dst non-zero */

    /* ---- PART 4: POSITIVE control (teeth for parts 2 and 3). -----
     * Without positive arms the negative results could pass on a
     * stuck-zero (dead path returning 0 for everything). */

    /* Slot 5 is PRIMITIVE_COMPOSE, registered in meta_register_all.
     * pattern_table_get must return non-zero, and pattern_id of that
     * pointer must be non-zero. */
    let pos_p : u64 = pattern_table_get(5u32)
    if pos_p == 0u64 { return 11u64 }  /* positive arm: slot 5 must exist */
    let pos_id : u64 = pattern_id(pos_p)
    if pos_id == 0u64 { return 12u64 } /* positive arm: pid must be non-zero */

    /* Transform index 0 (slot 18, tp_iii_to_asm) has src_form == 1u8. */
    let tsrc : u8 = tp_table_get_src(0u32)
    if tsrc != 1u8 { return 13u64 }    /* positive arm: src_form must be 1 */

    return 99u64
}
